package com.pack;

public class checkingalphabet {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		char ch ='9';
		if(ch>='a'&&ch<='z' || ch>='A'&&ch<='Z') {
			System.out.println("It is an Alphabet");
		}
		else {
			System.out.println("Not an Alphabet");
		}

	}

}
